			current, ok = curr[parts[i]]
			if !ok {
				return nil, fmt.Errorf("path not found")
			}
		default:
			return nil, fmt.Errorf("path does not refer to an object")
		}
	}

	// Get the array and add the value if it's not already there
	switch arr := current.(type) {
	case []interface{}:
